package main

import (
	"fmt"
	"math/rand"
)

func randInt(min, max int) int {
	return min + rand.Intn(max-min+1)
}

func trigo(pen *Pen, comprimento float64){
	if comprimento < 10{
		return
	}
	for range 5{
		pen.Walk(comprimento)
		trigo(pen, comprimento)
		pen.Up()
		pen.Right(72)
		pen.Walk(-comprimento)
		pen.Down()
	}
}

func main() {
	pen := NewPen(1500, 1500)
	pen.SetPosition(750, 1500)
	pen.SetHeading(90)

	trigo(pen, 400)

	pen.SavePNG("tree.png")
	fmt.Println("PNG file created successfully.")
}
